 48	    kms?.clientCert?.stringData['tls.cert'] || ''
 49	  );
 50	  const [clientCertificateFile, setClientCertificateFile] = React.useState(
 51	    kms?.clientCertFile || ''
 52	  );
 53	  const [clientKey, setClientKey] = React.useState(
 54	    kms?.clientCert?.stringData['tls.key'] || ''
 55	  );
 56	  const [clientKeyFile, setClientKeyFile] = React.useState(
 57	    kms?.clientKeyFile || ''
 58	  );
