 72	  const vaultCACertTooltip = t(
 73	    `A PEM-encoded CA certificate file used to verify the Vault server's SSL certificate.`
 74	  );
 75	
 76	  const vaultClientCertTooltip = t(
 77	    `A PEM-encoded client certificate. This certificate is used for TLS communication with the Vault server.`
 78	  );
 79	
 80	  const vaultClientKeyTooltip = t(
 81	    `An unencrypted, PEM-encoded private key which corresponds to the matching client certificate provided with VAULT_CLIENT_CERT.`
 82	  );
 83	
 84	  const vaultTLSTooltip = t(
 85	    `The name to use as the SNI host when Data Foundation connecting via TLS to the Vault server.`
 86	  );
