199	            fieldId="kms-auth-path"
200	            label={t('Authentication Path')}
201	            className="ceph-advanced-kms__form-body"
202	            labelHelp={<FieldLevelHelp>{vaultAuthPath}</FieldLevelHelp>}
203	          >
204	            <TextInput
205	              value={authPath}
206	              onChange={(_ev, value) => setAuthPath(value)}
207	              type="text"
208	              id="kms-service-auth-path"
209	              name="kms-service-auth-path"
210	              data-test="kms-service-auth-path"
211	            />
212	          </FormGroup>
213	        )}
