268	                )}
269	              </HelperTextItem>
270	            </HelperText>
271	          </FormHelperText>
272	        </FormGroup>
273	        <FormGroup
274	          fieldId="kms-service-ca-cert"
275	          label={t('CA Certificate')}
276	          className="ceph-advanced-kms__form-body"
277	          labelHelp={<FieldLevelHelp>{vaultCACertTooltip}</FieldLevelHelp>}
278	        >
279	          <FileUpload
