290	            }}
291	            data-test="kms-service-ca-cert"
292	          />
293	        </FormGroup>
294	        <FormGroup
295	          fieldId="kms-service-cert"
296	          label={t('Client Certificate')}
297	          className="ceph-advanced-kms__form-body"
298	          labelHelp={<FieldLevelHelp>{vaultClientCertTooltip}</FieldLevelHelp>}
299	        >
300	          <FileUpload
301	            id="kms-service-cert"
302	            value={clientCertificate}
303	            filename={clientCertificateFile}
304	            hideDefaultPreview
305	            filenamePlaceholder={t('Upload a .PEM file here...')}
306	            onFileInputChange={(_ev, file) => updateClientCert(file, file.name)}
307	            dropzoneProps={{
308	              accept: { 'text/plain': ['.pem'] },
309	              maxSize: KMSMaxFileUploadSize,
310	              onDropRejected: () => setError(KMSFileSizeErrorMsg),
311	            }}
312	            data-test="kms-service-client-cert"
313	          />
314	        </FormGroup>
315	        <FormGroup
316	          fieldId="kms-service-key"
317	          label={t('Client Private Key')}
318	          className="ceph-advanced-kms__form-body"
319	          labelHelp={<FieldLevelHelp>{vaultClientKeyTooltip}</FieldLevelHelp>}
320	        >
321	          <FileUpload
322	            id="kms-service-key"
323	            value={clientKey}
324	            filename={clientKeyFile}
325	            hideDefaultPreview
326	            filenamePlaceholder={t('Upload a .PEM file here...')}
327	            onFileInputChange={(_ev, file) => updateClientKey(file, file.name)}
328	            dropzoneProps={{
329	              accept: { 'text/plain': ['.pem'] },
330	              maxSize: KMSMaxFileUploadSize,
331	              onDropRejected: () => setError(KMSFileSizeErrorMsg),
332	            }}
333	            data-test="kms-service-client-private-key"
334	          />
335	        </FormGroup>
336	      </ModalBody>
337	      <ModalFooter>
338	        <Button key="cancel" variant="secondary" onClick={closeModal}>
339	          {t('Cancel')}
340	        </Button>
341	        <Button
342	          key="Save"
343	          variant="primary"
344	          data-test="save-kms-action"
345	          onClick={submit}
346	          isDisabled={!!error}
347	        >
348	          {t('Save')}
349	        </Button>
350	      </ModalFooter>
351	    </Modal>
352	  );
353	};
354	
355	export default AdvancedVaultModal;

